{
  "experiment_name": "AX-CPT Strategy Training",
  "description": "Experiment inducing proactive control shifts in the AX-CPT task via strategy training across two sessions.",
  "software_environment": "PsychoPy",
  "global_parameters": {
    "screen_background_color": "black",
    "stimulus_text_color": "white",
    "stimulus_position": "center",
    "timing_ms": {
      "cue_duration": 1000,
      "isi_duration": 4000,
      "probe_duration": 500,
      "iti_duration": 1000,
      "response_window": 1500
    },
    "stimuli_sets": {
      "cue_letters": "All uppercase letters excluding 'X', 'K', 'Y'",
      "probe_letters": "All uppercase letters excluding 'A', 'K', 'Y'",
      "mask_symbol": "*****"
    },
    "response_mapping": {
      "target_response": {
        "condition": "Cue='A' AND Probe='X'",
        "finger": "Right Middle Finger",
        "key": "k"
      },
      "non_target_response": {
        "condition": "All other combinations (AY, BX, BY)",
        "finger": "Right Index Finger",
        "key": "f"
      }
    }
  },
  "trial_structure": {
    "sequence": [
      {
        "stage": "Cue Presentation",
        "content": "cue_letter",
        "duration_ms": 1000,
        "allow_response": false
      },
      {
        "stage": "Inter-Stimulus Interval",
        "content": "blank_screen",
        "duration_ms": 4000,
        "allow_response": false,
        "note": "Critical window for proactive preparation"
      },
      {
        "stage": "Probe Presentation",
        "content": "probe_letter",
        "duration_ms": 500,
        "allow_response": true,
        "response_deadline_ms": 1500
      },
      {
        "stage": "Inter-Trial Interval",
        "content": "mask_symbol",
        "duration_ms": 1000,
        "allow_response": false
      }
    ],
    "trial_types_distribution_per_block": {
      "AX": 0.40,
      "AY": 0.10,
      "BX": 0.10,
      "BY": 0.40
    },
    "block_size": 50
  },
  "data_logging_columns": [
    "session_id",
    "block_num",
    "trial_num",
    "cue_letter",
    "probe_letter",
    "trial_type",
    "response_key",
    "correctness",
    "reaction_time",
    "condition"
  ],
  "protocol": {
    "sessions": [
      {
        "session_id": 1,
        "name": "Baseline Session",
        "interval_to_next": "4-14 days",
        "stages": [
          {
            "stage_name": "instruction",
            "type": "text_screen",
            "content": [
              "Welcome to the experiment.",
              "You will see a sequence of two letters.",
              "Rule: Press the MIDDLE KEY only if the first letter is 'A' AND the second letter is 'X'.",
              "For all other combinations, press the LEFT KEY.",
              "Do not press any key until you see the SECOND letter."
            ],
            "duration_seconds": null,
            "wait_for_key": true
          },
          {
            "stage_name": "demonstration",
            "type": "static_display",
            "content": "Visual examples of AX (Target), AY, BX, and BY trials with correct keys indicated."
          },
          {
            "stage_name": "practice",
            "type": "task_block",
            "trials_count": 10,
            "feedback_mode": "experimenter_observation_or_simple_feedback",
            "criteria_to_proceed": "Understand rules; retry if error rate is high."
          },
          {
            "stage_name": "formal_experiment",
            "type": "task_blocks",
            "blocks_count": 4,
            "trials_per_block": 50,
            "total_trials": 200,
            "condition_label": "Baseline",
            "feedback_mode": "none",
            "break_between_blocks": true
          },
          {
            "stage_name": "ending",
            "type": "text_screen",
            "content": [
              "Session 1 complete.",
              "Please return in 4 to 14 days for the second session.",
              "Thank you."
            ],
            "save_data": true
          }
        ]
      },
      {
        "session_id": 2,
        "name": "Strategy Training Session",
        "stages": [
          {
            "stage_name": "pre_test",
            "type": "task_block",
            "blocks_count": 1,
            "trials_per_block": 50,
            "condition_label": "Baseline",
            "feedback_mode": "none",
            "purpose": "Immediate baseline measurement before training"
          },
          {
            "stage_name": "strategy_instruction",
            "type": "text_screen",
            "content": [
              "STRATEGY TRAINING:",
              "Note that 'X' follows 'A' very frequently (80% of the time).",
              "When you see 'A': During the blank screen, mentally prepare to press the MIDDLE KEY.",
              "When you see any other letter: During the blank screen, prepare to press the LEFT KEY.",
              "Use the cue to get ready BEFORE the second letter appears."
            ],
            "duration_seconds": null,
            "wait_for_key": true
          },
          {
            "stage_name": "training_practice",
            "type": "task_block",
            "trials_count": 60,
            "condition_label": "Strategy_Training",
            "feedback_mode": "reinforcing",
            "purpose": "Practice applying the proactive strategy"
          },
          {
            "stage_name": "post_test",
            "type": "task_blocks",
            "blocks_count": 3,
            "trials_per_block": 50,
            "total_trials": 150,
            "condition_label": "Strategy_Training",
            "feedback_mode": "none",
            "instruction_reminder": "Continue using the strategy learned."
          },
          {
            "stage_name": "ending",
            "type": "text_screen",
            "content": [
              "Experiment Complete.",
              "Thank you for your participation."
            ],
            "save_data": true
          }
        ]
      }
    ]
  },
  "implementation_notes": {
    "randomization": "Pre-generate CSV conditions files for each block to ensure exact 40/10/10/40 distribution with pseudo-random ordering.",
    "timing_precision": "Ensure ISI (4000ms) is precise and not affected by drawing refresh rates.",
    "feedback_policy": "No trial-by-trial visual feedback in formal blocks (only in practice/training if specified).",
    "exclusion_criteria_flagging": "Log data normally; mark rows for potential exclusion later if AX error > 40% or AY error = 100%."
  }
}
